# 宠物基类
class Pet:
    def __init__(self, name):
        self.name = name
        self.level = 1

    def speak(self):
        print(f"{self.name} 发出声音~")

# 火龙子类
class FireDragon(Pet):
    def __init__(self, name):
        super().__init__(name)
        self.element = "火"

    def speak(self):
        print(f"{self.name}: 吼！🔥")

    def breathe_fire(self):
        print(f"{self.name} 喷出火焰！造成50点火焰伤害！")

# 冰龙子类
class IceDragon(Pet):
    def __init__(self, name):
        super().__init__(name)
        self.element = "冰"

    def speak(self):
        print(f"{self.name}: 吼！❄️")

    def breathe_ice(self):
        print(f"{self.name} 喷出冰霜！造成50点冰冻伤害！")

# 测试
fire_dragon = FireDragon("小火龙")
ice_dragon = IceDragon("冰灵龙")

fire_dragon.speak()
fire_dragon.breathe_fire()

ice_dragon.speak()
ice_dragon.breathe_ice()

